-- CNB Primaria - Comunicación y Lenguaje L 3 (idioma extranjero) - Cuarto, Quinto y Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Comunicación_y_Lenguaje_L_3_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Cuarto Grado
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '1. Utiliza el lenguaje verbal y no verbal en la comunicación de textos orales relativos a situaciones cercanas a su realidad.', ARRAY['1.1. Sigue instrucciones orales.', '1.2. Ordena hechos para formar secuencias siguiendo parámetros temporales.', '1.3. Utiliza las expresiones de acuerdo a la particularidad del momento.', '1.4. Infiere significados de la información no verbal del contexto.', '1.5. Clasifica diferentes tipos de texto con los que trabaja de forma cotidiana.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '2. Produce textos orales con la pronunciación, el ritmo y la entonación propios del tercer idioma.', ARRAY['2.1. Se comunica mediante mensajes sencillos empleando los recursos a su alcance.', '2.2. Da respuestas breves a las preguntas que se le hacen.', '2.3. Pronuncia, correctamente, las palabras del vocabulario básico.', '2.4. Utiliza, en sus conversaciones o respuestas a preguntas, las palabras del vocabulario básico aprendido.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '3. Lee en forma comprensiva unidades mínimas de texto, estableciendo relaciones elementales entre texto y significado.', ARRAY['3.1. Reconoce palabras del vocabulario por su grafía.', '3.2. Interpreta frases de textos cortos.', '3.3. Infiere el significado de palabras específicas en frases y oraciones.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '4. Produce textos escritos breves y sencillos apegándose a las normas de la lengua extranjera.', ARRAY['4.1. Utiliza correctamente las grafías.', '4.2. Escribe palabras con el orden correspondiente.', '4.3. Escribe datos personales en el tercer idioma.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '5. Reconoce que un idioma extranjero es la expresión de una nueva cultura.', ARRAY['5.1. Identifica la influencia de la lengua extranjera en la lengua materna.', '5.2. Contrasta fonemas de la L 1 y L 3.', '5.3. Identifica diferencias elementales en las costumbres culturales propias y las de la lengua extranjera.', '5.4. Muestra respeto por las expresiones lingüísticas y culturales en la lengua extranjera.']),

-- Quinto Grado
('Quinto Grado', 'Comunicación y Lenguaje L 3', '1. Utiliza, en su comunicación, textos orales referentes a situaciones, acontecimientos y objetos próximos.', ARRAY['1.1. Interpreta canciones, rimas e historias cortas, entre otras.', '1.2. Asocia imágenes y grafías.', '1.3. Expresa sus gustos y preferencias utilizando la L 3.', '1.4. Amplía el vocabulario que maneja en las situaciones comunicativas.']),
('Quinto Grado', 'Comunicación y Lenguaje L 3', '2. Establece la relación entre el significado, la pronunciación, el ritmo y la entonación y la representación gráfica de palabras y frases sencillas.', ARRAY['2.1. Evidencia la importancia de una correcta pronunciación y entonación para la comunicación.', '2.2. Utiliza las palabras nuevas para elaborar sus mensajes.']),
('Quinto Grado', 'Comunicación y Lenguaje L 3', '3. Lee en forma comprensiva sus producciones escritas así como las señalizaciones, anuncios y mensajes básicos.', ARRAY['3.1. Ordena convenientemente los diferentes fragmentos de una historia dada.', '3.2. Identifica personajes en historias, cuentos y canciones.']),
('Quinto Grado', 'Comunicación y Lenguaje L 3', '4. Produce textos escritos breves de su entorno personal y familiar.', ARRAY['4.1. Maneja correctamente la ortografía de las palabras.', '4.2. Redacta textos sencillos utilizando el vocabulario aprendido.']),
('Quinto Grado', 'Comunicación y Lenguaje L 3', '5. Respeta las costumbres y tradiciones que implica el idioma en aprendizaje.', ARRAY['5.1. Establece la diferencia entre aspectos de la realidad cotidiana transmitidos por la lengua extranjera y las costumbres de su propia cultura.', '5.2. Utiliza saludos y despedidas adecuados a la situación.']),

-- Sexto Grado
('Sexto Grado', 'Comunicación y Lenguaje L 3', '1. Comunica la información global y específica de textos orales y escritos, sobre situaciones y acontecimientos de su entorno.', ARRAY['1.1. Utiliza el vocabulario en situaciones comunicativas recreadas en el aula.', '1.2. Interpreta información oral y escrita y la emplea con fines prácticos.', '1.3. Emplea el idioma para resolver dudas en los intercambios comunicativos.']),
('Sexto Grado', 'Comunicación y Lenguaje L 3', '2. Establece relaciones entre el significado, la pronunciación y la representación gráfica del vocabulario de los aspectos sonoros, del ritmo y de la entonación.', ARRAY['2.1. Reproduce espontáneamente la pronunciación correcta de las palabras.', '2.2. Describe los elementos básicos de la estructura gramatical.']),
('Sexto Grado', 'Comunicación y Lenguaje L 3', '3. Lee en forma comprensiva textos cortos y sencillos, previamente trabajados de forma oral, relacionados con sus experiencias e intereses.', ARRAY['3.1. Emplea la información contenida en los textos que se le proporcionan para construir otra información.', '3.2. Lee textos de manera espontánea.', '3.3. Sigue instrucciones expresadas por escrito.']),
('Sexto Grado', 'Comunicación y Lenguaje L 3', '4. Produce textos escritos sencillos sobre temas conocidos respetando las normas gramaticales del idioma en estudio.', ARRAY['4.1. Escribe textos cortos y sencillos de acuerdo con los patrones gramaticales básicos del idioma.', '4.2. Aplica los diferentes elementos gramaticales en producciones escritas cortas.', '4.3. Describe los elementos básicos de la estructura gramatical.']),
('Sexto Grado', 'Comunicación y Lenguaje L 3', '5. Incorpora elementos culturales por medio del idioma de acuerdo con las costumbres y modos de vida de los nativos del idioma en estudio.', ARRAY['5.1. Participa activa y voluntariamente en actividades de lectura.', '5.2. Se interesa por conocer personajes importantes de donde proviene el idioma en estudio.', '5.3. Emplea saludos y normas de cortesía adecuados a la situación.']);
